import React, { useState } from 'react';

function SignUp() {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: ''
  });

  const handleSignUp = async (e) => {
    e.preventDefault();
    try {
      const response = await fetch('http://127.0.0.1:5000/api/signup', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData),
      });

      const result = await response.json();
      if (response.ok) {
        alert("Pendaftaran Berhasil! Silakan masuk.");
        window.location.href = "/"; 
      } else {
        alert(result.message);
      }
    } catch (error) {
      alert("Gagal terhubung ke server. Pastikan Flask jalan!");
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h1 style={styles.title}>Sign up</h1>
        <p style={styles.subtitle}>Daftar akun untuk melanjutkan</p>

        <form onSubmit={handleSignUp}>
          {/* INPUT NAMA */}
          <div style={styles.inputGroup}>
            <label style={styles.label}>Nama Lengkap</label>
            <input 
              type="text" 
              placeholder="Contoh: Ferdi Gunawan" 
              style={styles.input}
              onChange={(e) => setFormData({...formData, name: e.target.value})}
              required 
            />
          </div>

          {/* INPUT EMAIL */}
          <div style={styles.inputGroup}>
            <label style={styles.label}>Alamat Email</label>
            <input 
              type="email" 
              placeholder="Contoh: admin@gmail.com" 
              style={styles.input}
              onChange={(e) => setFormData({...formData, email: e.target.value})}
              required 
            />
          </div>
          
          {/* INPUT PASSWORD */}
          <div style={styles.inputGroup}>
            <label style={styles.label}>Password</label>
            <input 
              type="password" 
              placeholder="Masukkan password minimal 6 karakter" 
              style={styles.input}
              onChange={(e) => setFormData({...formData, password: e.target.value})}
              required 
            />
          </div>
          
          <button type="submit" style={styles.button}>Sign up</button>
        </form>

        <p style={styles.footerText}>
          Sudah punya akun? <a href="/" style={styles.link}>Sign in</a>
        </p>
      </div>
    </div>
  );
}

const styles = {
  container: { display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh', backgroundColor: '#f9f9f9' },
  card: { padding: '40px', borderRadius: '10px', backgroundColor: '#fff', boxShadow: '0 4px 20px rgba(0,0,0,0.08)', width: '100%', maxWidth: '450px' },
  title: { fontSize: '32px', textAlign: 'center', marginBottom: '10px', fontWeight: '500' },
  subtitle: { textAlign: 'center', color: '#666', marginBottom: '30px' },
  inputGroup: { marginBottom: '20px' },
  label: { display: 'block', marginBottom: '8px', fontSize: '14px', color: '#333', fontWeight: 'bold' },
  input: { 
    width: '100%', 
    padding: '12px 0px', 
    fontSize: '16px', 
    border: 'none', 
    borderBottom: '1px solid #ccc', 
    outline: 'none',
    boxSizing: 'border-box'
  },
  button: { 
    width: '100%', 
    padding: '12px', 
    backgroundColor: '#1976d2', 
    color: 'white', 
    border: 'none', 
    borderRadius: '5px', 
    fontSize: '16px', 
    cursor: 'pointer', 
    marginTop: '20px',
    fontWeight: 'bold'
  },
  footerText: { textAlign: 'center', marginTop: '20px', color: '#666', fontSize: '14px' },
  link: { color: '#1976d2', textDecoration: 'none', fontWeight: 'bold' }
};

export default SignUp;
